import re, glob
mychaps=sorted(glob.glob('Cohomology_*.tex')+glob.glob('RiemannRoch_*.tex'))
env_begin=re.compile(r'\\begin\{(definition|lemma|theorem|proposition|corollary|remark|proof|instance|example|conjecture)\}')
env_end=re.compile(r'\\end\{(definition|lemma|theorem|proposition|corollary|remark|proof|instance|example|conjecture)\}')
label_re=re.compile(r'\\label\{([^}]+)\}')
uses_re=re.compile(r'\\uses\{([^}]*)\}')
def parse(f):
    txt=open(f).read()
    # tokenize by scanning
    pos=0; stack=[]; blocks=[]; cur=None
    # We'll walk line by line tracking environment
    # Simpler: iterate over all begin/end/label/uses in order
    toks=[]
    for m in re.finditer(r'\\begin\{(\w+)\}|\\end\{(\w+)\}|\\label\{([^}]+)\}|\\uses\{([^}]*)\}', txt):
        toks.append(m)
    envstack=[]
    statements=[]  # list of dict: label, kind, stmt_uses(set), proof_uses(set)
    last_stmt=None
    for m in toks:
        b,e,lab,us=m.group(1),m.group(2),m.group(3),m.group(4)
        if b:
            envstack.append(b)
            if b in ('definition','lemma','theorem','proposition','corollary','instance','example','conjecture'):
                last_stmt={'label':None,'kind':b,'stmt_uses':set(),'proof_uses':set()}
                statements.append(last_stmt)
        elif e:
            if envstack: envstack.pop()
        elif lab:
            if envstack and envstack[-1] in ('definition','lemma','theorem','proposition','corollary','instance','example','conjecture') and last_stmt is not None:
                last_stmt['label']=lab
        elif us is not None:
            deps=set(x.strip() for x in us.split(',') if x.strip())
            inproof = envstack and envstack[-1]=='proof'
            instmt = envstack and envstack[-1] in ('definition','lemma','theorem','proposition','corollary','instance','example','conjecture')
            if instmt and last_stmt is not None:
                last_stmt['stmt_uses']|=deps
            elif inproof and last_stmt is not None:
                last_stmt['proof_uses']|=deps
    return statements
for f in mychaps:
    sts=parse(f)
    issues=[s for s in sts if s['label'] and (s['proof_uses']-s['stmt_uses'])]
    nolab=[s for s in sts if not s['label']]
    print("### %s  (blocks=%d)"%(f,len(sts)))
    for s in issues:
        missing=s['proof_uses']-s['stmt_uses']
        print("   COPYUP %s  +%s"%(s['label'], sorted(missing)))
    if nolab: print("   (%d unlabeled blocks)"%len(nolab))
